mapper.select:
SELECT u.*, p.part_name, e.equipment_name
FROM part_usages u
LEFT JOIN parts p ON u.part_code = p.part_code
LEFT JOIN equipment e ON u.equipment_code = e.equipment_code


        AND u.usage_date >= #{dateFrom}


        AND u.usage_date <= #{dateTo}


        AND e.equipment_type = #{equipmentType}


        AND u.part_code = #{partCode}


ORDER BY u.usage_date DESC, u.usage_id DESC

    LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM part_usages u
LEFT JOIN equipment e ON u.equipment_code = e.equipment_code


        AND u.usage_date >= #{dateFrom}


        AND u.usage_date <= #{dateTo}


        AND e.equipment_type = #{equipmentType}


        AND u.part_code = #{partCode}
